const DEFAULT_CONFIG = {
  referral_url: "https://aigate.shop",
  durations: Array.from({ length: 12 }, (_, index) => index + 4),
  resolutions: ["480p", "720p", "1080p"],
  ratios: ["Auto", "16:9", "4:3", "1:1", "3:4", "9:16", "21:9"],
  qualities: ["fast", "standard"],
  model_modes: {
    fast: {
      id: "bytedance/seedance-2.0-fast",
      label: "Fast",
      description: "Быстрее и дешевле, удобно для потока.",
      pricing: {
        "480p": 0.01614,
        "720p": 0.0363,
        "1080p": 0.08166,
      },
    },
    standard: {
      id: "bytedance/seedance-2.0",
      label: "Standard",
      description: "Выше качество, обычно дороже и дольше.",
      pricing: {
        "480p": 0.020178,
        "720p": 0.04536,
        "1080p": 0.10206,
      },
    },
  },
  max_image_references: 6,
  max_upload_mb: 16,
  max_prompt_length: 1000,
};

const CAMERA_PRESETS = [
  { group: "Basic lens", presets: [
    "Move the camera around the subject",
    "Fixed lens",
    "Handheld lens",
    "Zoom out",
    "Advance",
    "Follow",
    "Shake right",
    "Shake left",
    "Shake up",
    "Shake down",
    "Surround",
  ]},
  { group: "Cinematic", presets: [
    "Slow dolly in",
    "Dolly zoom (Vertigo)",
    "Aerial drone shot",
    "Low angle tracking",
    "Bird's eye view",
    "Dutch angle",
  ]},
];

const STATUS_LABELS = {
  pending: "Ожидает",
  processing: "В работе",
  completed: "Готово",
  failed: "Ошибка",
};

function aspectValue(ratio) {
  if (!ratio || ratio === "Auto") return "16 / 9";
  return ratio.includes(":") ? ratio.replace(":", " / ") : "16 / 9";
}

function formatTime(seconds) {
  const safe = Math.max(0, Math.floor(seconds || 0));
  const minutes = String(Math.floor(safe / 60)).padStart(2, "0");
  const rest = String(safe % 60).padStart(2, "0");
  return `${minutes}:${rest}`;
}

function money(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return "по тарифу AIGate";
  return `$${numeric.toFixed(5)} / sec`;
}

// ─── @-mention helpers ───────────────────────────────────────────────────────

function buildAtMenu(imageFiles, videoFile, audioFile) {
  const items = [];
  imageFiles.forEach((file, index) => {
    items.push({
      id: `img_${index}`,
      label: `reference ${index + 1}`,
      fileName: file.name,
      tag: "фото",
      type: "image",
      ordinal: index + 1,
    });
  });
  if (videoFile) {
    items.push({
      id: "vid_0",
      label: "video reference",
      fileName: videoFile.name,
      tag: "видео",
      type: "video",
      ordinal: "V",
    });
  }
  if (audioFile) {
    items.push({
      id: "aud_0",
      label: "audio reference",
      fileName: audioFile.name,
      tag: "аудио",
      type: "audio",
      ordinal: "A",
    });
  }
  return items;
}

function AtMenu({ items, onSelect, style }) {
  if (!items.length) return null;
  return (
    <div className="at-menu" style={style}>
      {["image", "video", "audio"].map((type) => {
        const group = items.filter((i) => i.type === type);
        if (!group.length) return null;
        const groupLabel = type === "image" ? "Images" : type === "video" ? "Videos" : "Audios";
        return (
          <div key={type}>
            <div className="at-group-label">{groupLabel}</div>
            {group.map((item) => (
              <button key={item.id} className="at-item" onMouseDown={() => onSelect(item)}>
                <span className={`at-icon at-icon--${item.type}`} aria-hidden="true">
                  {item.ordinal}
                </span>
                <span className="at-item-copy">
                  <span className="at-item-name">{item.label}</span>
                  <span className="at-item-file">{item.fileName}</span>
                </span>
                <span className="at-item-tag">[{item.tag}]</span>
              </button>
            ))}
          </div>
        );
      })}
    </div>
  );
}

function PromptTextarea({ value, onChange, maxLength, imageFiles, videoFile, audioFile }) {
  const textareaRef = useRef(null);
  const [showAtMenu, setShowAtMenu] = useState(false);
  const [atQuery, setAtQuery] = useState("");

  const atItems = useMemo(
    () => buildAtMenu(imageFiles, videoFile, audioFile),
    [imageFiles, videoFile, audioFile]
  );

  const filteredItems = useMemo(
    () => atItems.filter((item) => {
      const query = atQuery.toLowerCase();
      return (
        item.label.toLowerCase().includes(query) ||
        item.fileName.toLowerCase().includes(query) ||
        item.tag.toLowerCase().includes(query)
      );
    }),
    [atItems, atQuery]
  );

  function handleChange(e) {
    const val = e.target.value;
    onChange(val);

    const cursor = e.target.selectionStart;
    const textBefore = val.slice(0, cursor);
    const atMatch = textBefore.match(/@(\w*)$/);
    if (atMatch && atItems.length) {
      setAtQuery(atMatch[1] || "");
      setShowAtMenu(true);
    } else {
      setShowAtMenu(false);
    }
  }

  function handleSelect(item) {
    const cursor = textareaRef.current.selectionStart;
    const textBefore = value.slice(0, cursor);
    const textAfter = value.slice(cursor);
    const atStart = textBefore.lastIndexOf("@");
    const insertion = `@${item.label} [${item.tag}]`;
    const newValue = textBefore.slice(0, atStart) + insertion + " " + textAfter;
    onChange(newValue);
    setShowAtMenu(false);
    textareaRef.current.focus();
  }

  function handleKeyDown(e) {
    if (showAtMenu && (e.key === "Escape" || e.key === "Enter")) {
      setShowAtMenu(false);
    }
  }

  return (
    <div className="prompt-wrap">
      <textarea
        ref={textareaRef}
        value={value}
        maxLength={maxLength}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        onBlur={() => setTimeout(() => setShowAtMenu(false), 150)}
        placeholder="Опишите кадр... Используйте @ для вставки референсов"
      />
      {showAtMenu && (
        <AtMenu items={filteredItems.length ? filteredItems : atItems} onSelect={handleSelect} />
      )}
    </div>
  );
}

// ─── Camera Presets ───────────────────────────────────────────────────────────

function CameraPresets({ onSelect }) {
  const [open, setOpen] = useState(false);
  return (
    <div className="camera-wrap">
      <button className="text-button camera-btn" type="button" onClick={() => setOpen((v) => !v)}>
        {open ? "Скрыть пресеты камеры" : "🎥 Пресеты камеры"}
      </button>
      {open && (
        <div className="camera-presets-panel">
          {CAMERA_PRESETS.map((group) => (
            <div key={group.group} className="preset-group">
              <div className="preset-group-label">{group.group}</div>
              <div className="preset-pills">
                {group.presets.map((p) => (
                  <button
                    key={p}
                    type="button"
                    className="preset-pill"
                    onClick={() => { onSelect(p); setOpen(false); }}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── Main App ─────────────────────────────────────────────────────────────────

export default function App() {
  const tg = window.Telegram?.WebApp;
  const tgUser = tg?.initDataUnsafe?.user;
  const imageInputRef = useRef(null);
  const videoInputRef = useRef(null);
  const audioInputRef = useRef(null);

  const [page, setPage] = useState("generate");
  const [config, setConfig] = useState(DEFAULT_CONFIG);
  const [hasKey, setHasKey] = useState(false);
  const [balance, setBalance] = useState("");
  const [balanceRaw, setBalanceRaw] = useState(null);
  const [history, setHistory] = useState([]);
  const [notice, setNotice] = useState("");
  const [error, setError] = useState("");
  const [booting, setBooting] = useState(true);
  const [checkingBalance, setCheckingBalance] = useState(false);

  const [modelMode, setModelMode] = useState("fast");
  const [prompt, setPrompt] = useState("");
  const [negativePrompt, setNegativePrompt] = useState("");
  const [duration, setDuration] = useState(5);
  const [resolution, setResolution] = useState("720p");
  const [ratio, setRatio] = useState("16:9");
  const [audio, setAudio] = useState(false);
  const [seed, setSeed] = useState("");
  const [imageFiles, setImageFiles] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);
  const [videoFile, setVideoFile] = useState(null);
  const [videoPreview, setVideoPreview] = useState("");
  const [audioFile, setAudioFile] = useState(null);
  const [audioPreview, setAudioPreview] = useState("");
  const [advancedOpen, setAdvancedOpen] = useState(false);

  const [generation, setGeneration] = useState(null);
  const [generationStartedAt, setGenerationStartedAt] = useState(null);
  const [now, setNow] = useState(Date.now());
  const [submitting, setSubmitting] = useState(false);

  const activeMode = config.model_modes?.[modelMode] || DEFAULT_CONFIG.model_modes.fast;
  const estimatedCost = useMemo(() => {
    const perSecond = Number(activeMode?.pricing?.[resolution] || 0);
    if (!perSecond) return null;
    return duration * perSecond;
  }, [activeMode, duration, resolution]);

  const shownProgress = useMemo(() => {
    if (!generation) return 0;
    if (generation.status === "completed" || generation.status === "failed") return 100;
    const elapsed = generationStartedAt ? (now - generationStartedAt) / 1000 : 0;
    const timerProgress = Math.min(95, 8 + (elapsed / 900) * 87);
    return Math.max(generation.progress || 0, Math.round(timerProgress));
  }, [generation, generationStartedAt, now]);

  const elapsedSeconds = generationStartedAt ? Math.floor((now - generationStartedAt) / 1000) : 0;

  const loadHistory = useCallback(async () => {
    if (!isTelegramReady()) return;
    const payload = await fetchHistory(8);
    setHistory(payload.generations || []);
  }, []);

  const loadBalance = useCallback(async () => {
    if (!isTelegramReady()) {
      setBooting(false);
      return;
    }
    setCheckingBalance(true);
    try {
      const payload = await fetchBalance();
      setHasKey(Boolean(payload.has_key));
      setBalance(payload.balance || "");
      setBalanceRaw(payload.raw || null);
      if (payload.error) setError(errorMessage(payload.error));
    } catch (caught) {
      setError(errorMessage(caught));
    } finally {
      setBooting(false);
      setCheckingBalance(false);
    }
  }, []);

  useEffect(() => {
    tg?.ready();
    tg?.expand();
    fetchConfig()
      .then((payload) => {
        const merged = { ...DEFAULT_CONFIG, ...payload };
        setConfig(merged);
        setModelMode((current) => (merged.qualities.includes(current) ? current : merged.qualities[0] || "fast"));
        setDuration((current) => (merged.durations.includes(current) ? current : merged.durations[0] || 5));
      })
      .catch(() => setConfig(DEFAULT_CONFIG));
    loadBalance();
    loadHistory().catch(() => {});
    const socket = connectWebSocket((message) => {
      setGeneration((current) => ({
        id: message.generation_id,
        status: message.status,
        message: errorMessage(message.message, "Ошибка генерации"),
        progress: message.progress || current?.progress || 0,
        resultUrl: absoluteUrl(message.result_url),
      }));
      if (message.status === "completed" || message.status === "failed") {
        setSubmitting(false);
        loadHistory().catch(() => {});
        loadBalance().catch(() => {});
      }
    });
    return () => socket?.close();
  }, [loadBalance, loadHistory, tg]);

  useEffect(() => {
    if (!submitting && generation?.status !== "processing") return;
    const timer = window.setInterval(() => setNow(Date.now()), 1000);
    return () => window.clearInterval(timer);
  }, [generation?.status, submitting]);

  useEffect(() => {
    const next = imageFiles.map((file) => ({ url: URL.createObjectURL(file), name: file.name }));
    setImagePreviews(next);
    return () => next.forEach((item) => URL.revokeObjectURL(item.url));
  }, [imageFiles]);

  useEffect(() => {
    if (!videoFile) { setVideoPreview(""); return; }
    const url = URL.createObjectURL(videoFile);
    setVideoPreview(url);
    return () => URL.revokeObjectURL(url);
  }, [videoFile]);

  useEffect(() => {
    if (!audioFile) { setAudioPreview(""); return; }
    const url = URL.createObjectURL(audioFile);
    setAudioPreview(url);
    return () => URL.revokeObjectURL(url);
  }, [audioFile]);

  function addImageFiles(fileList) {
    const incoming = Array.from(fileList || []).filter((file) => file.type.startsWith("image/"));
    setImageFiles((current) => [...current, ...incoming].slice(0, config.max_image_references));
  }

  function removeImage(index) {
    setImageFiles((current) => current.filter((_, i) => i !== index));
  }

  function appendToPrompt(text) {
    setPrompt((current) => {
      const sep = current && !current.endsWith(" ") ? " " : "";
      return current + sep + text + " ";
    });
  }

  async function handleGenerate() {
    setError("");
    setNotice("");
    if (!isTelegramReady()) {
      setError("Откройте Mini App внутри Telegram, чтобы backend получил подпись пользователя.");
      return;
    }
    if (!hasKey) { setPage("profile"); setError("Сначала подключите API-ключ AIGate."); return; }
    if (!prompt.trim()) { setError("Введите промпт для видео."); return; }
    setSubmitting(true);
    setGenerationStartedAt(Date.now());
    setNow(Date.now());
    setGeneration({ id: null, status: "processing", message: "Отправляем задачу на backend.", progress: 8, resultUrl: "" });
    try {
      const payload = await submitGeneration({ modelMode, prompt: prompt.trim(), duration, resolution, ratio, audio, negativePrompt, seed, imageFiles, videoFile, audioFile });
      setGeneration((current) => ({ ...current, id: payload.generation_id, message: `Задача #${payload.generation_id} запущена. Оставьте окно открытым.`, progress: 14 }));
      setNotice("Генерация запущена.");
    } catch (caught) {
      setSubmitting(false);
      const message = errorMessage(caught);
      setGeneration((current) => ({ ...current, status: "failed", message, progress: 100 }));
      setError(message);
    }
  }

  async function handleSaveKey(apiKey) {
    setError(""); setNotice("");
    try {
      const payload = await setApiKey(apiKey);
      setNotice("Ключ подключён. Баланс проверен.");
      setHasKey(true);
      setBalance(payload.balance || "");
      setBalanceRaw(payload.raw || null);
      setPage("generate");
      await loadHistory();
    } catch (caught) {
      setError(errorMessage(caught));
    }
  }

  return (
    <div className="app-shell">
      <header className="topbar">
        <div className="brand-mark cat-avatar"><img src={CAT_AVATAR} alt="Sami" /></div>
        <div className="brand-copy">
          <div className="eyebrow">{tgUser ? `@${tgUser.username || tgUser.first_name}` : "@demo_user"}</div>
          <h1>Sami Studio</h1>
        </div>
        <div className={`key-chip ${hasKey ? "ready" : ""}`}>{hasKey ? "ключ активен" : "нет ключа"}</div>
      </header>

      <section className="balance-strip">
        <div>
          <span>Баланс</span>
          <strong>{balance ? balance.split("\n")[0] : hasKey ? "проверяем" : "ключ не подключён"}</strong>
        </div>
        <button type="button" onClick={loadBalance} disabled={checkingBalance || !isTelegramReady()}>
          {checkingBalance ? "Проверка" : "Проверить"}
        </button>
      </section>

      <nav className="tabs" aria-label="Меню">
        <button className={page === "generate" ? "active" : ""} onClick={() => setPage("generate")}>Генерация</button>
        <button className={page === "profile" ? "active" : ""} onClick={() => setPage("profile")}>Профиль</button>
      </nav>

      {!isTelegramReady() && (
        <div className="notice-panel muted">
          Это локальный просмотр. В Telegram Mini App появится авторизация, баланс и запуск генерации.
        </div>
      )}
      {error && <div className="notice-panel danger">{error}</div>}
      {notice && <div className="notice-panel success">{notice}</div>}

      {page === "generate" && (
        <main className="workspace">
          {/* Preview stage */}
          <section className="preview-stage" style={{ "--stage-ratio": aspectValue(ratio) }}>
            {imagePreviews[0] ? (
              <img src={imagePreviews[0].url} alt="Главный фото-референс" />
            ) : videoPreview ? (
              <video src={videoPreview} muted playsInline />
            ) : (
              <div className="empty-frame">
                <span>Preview</span>
                <strong>{ratio}</strong>
              </div>
            )}
            <div className="stage-overlay">
              <span>{activeMode.label}: {activeMode.id}</span>
              <span>{duration} c / {resolution} / {ratio}</span>
            </div>
          </section>

          {/* Model mode */}
          <section className="panel">
            <div className="section-title">
              <span>Режим качества</span>
              <small>{money(activeMode.pricing?.[resolution])}</small>
            </div>
            <div className="mode-grid">
              {config.qualities.map((modeKey) => {
                const item = config.model_modes?.[modeKey] || DEFAULT_CONFIG.model_modes[modeKey];
                return (
                  <button key={modeKey} type="button" className={`mode-card ${modelMode === modeKey ? "active" : ""}`} onClick={() => setModelMode(modeKey)}>
                    <strong>{item?.label || modeKey}</strong>
                    <span>{item?.description || ""}</span>
                    <small>{item?.id || ""}</small>
                  </button>
                );
              })}
            </div>
            <div className="cost-line">
              Расчёт: {estimatedCost ? `$${estimatedCost.toFixed(4)} ориентировочно` : "точное списание покажет AIGate"}
            </div>
          </section>

          {/* References */}
          <section className="panel">
            <div className="section-title">
              <span>Референсы</span>
              <small>{imageFiles.length}/{config.max_image_references} фото</small>
            </div>
            <input ref={imageInputRef} type="file" accept="image/*" multiple className="hidden-input" onChange={(e) => addImageFiles(e.target.files)} />
            <button className="dropzone" type="button" onClick={() => imageInputRef.current?.click()}>
              <span>Добавить фото-референсы</span>
              <small>до {config.max_image_references} шт.</small>
            </button>
            {imagePreviews.length > 0 && (
              <div className="reference-grid">
                {imagePreviews.map((item, index) => (
                  <div className="reference-tile" key={item.url}>
                    <img src={item.url} alt={`Фото ${index + 1}`} />
                    <span className="reference-badge">reference {index + 1}</span>
                    <button type="button" onClick={() => removeImage(index)} aria-label="Удалить фото">x</button>
                  </div>
                ))}
              </div>
            )}
            <div className="reference-actions">
              <input ref={videoInputRef} type="file" accept="video/*" className="hidden-input" onChange={(e) => setVideoFile(e.target.files?.[0] || null)} />
              <button type="button" onClick={() => videoInputRef.current?.click()}>
                {videoFile ? "Видео выбрано" : "Добавить видео-референс"}
              </button>
              <input ref={audioInputRef} type="file" accept="audio/*" className="hidden-input" onChange={(e) => setAudioFile(e.target.files?.[0] || null)} />
              <button type="button" onClick={() => audioInputRef.current?.click()}>
                {audioFile ? "Аудио выбрано" : "Добавить аудио-референс"}
              </button>
            </div>
            {(videoFile || audioFile) && (
              <div className="file-summary">
                {videoFile && (
                  <div>
                    <span>Видео:</span>
                    <strong>{videoFile.name}</strong>
                    <button type="button" onClick={() => setVideoFile(null)}>убрать</button>
                  </div>
                )}
                {audioFile && (
                  <div>
                    <span>Аудио:</span>
                    <strong>{audioFile.name}</strong>
                    <button type="button" onClick={() => setAudioFile(null)}>убрать</button>
                  </div>
                )}
                {audioPreview && <audio src={audioPreview} controls />}
              </div>
            )}
          </section>

          {/* Prompt with @-mentions */}
          <section className="panel">
            <div className="section-title">
              <span>Промпт</span>
              <small>{prompt.length}/{config.max_prompt_length}</small>
            </div>
            <PromptTextarea
              value={prompt}
              onChange={setPrompt}
              maxLength={config.max_prompt_length}
              imageFiles={imageFiles}
              videoFile={videoFile}
              audioFile={audioFile}
            />
            {/* @ quick-insert chips */}
            {(imageFiles.length > 0 || videoFile || audioFile) && (
              <div className="at-chips">
                <span className="at-chips-hint">@ упоминания:</span>
                {imageFiles.map((f, i) => (
                  <button key={i} type="button" className="at-chip at-chip--image"
                    title={f.name}
                    onClick={() => appendToPrompt(`@reference ${i + 1} [фото]`)}>
                    reference {i + 1}
                  </button>
                ))}
                {videoFile && (
                  <button type="button" className="at-chip at-chip--video"
                    title={videoFile.name}
                    onClick={() => appendToPrompt("@video reference [видео]")}>
                    video reference
                  </button>
                )}
                {audioFile && (
                  <button type="button" className="at-chip at-chip--audio"
                    title={audioFile.name}
                    onClick={() => appendToPrompt("@audio reference [аудио]")}>
                    audio reference
                  </button>
                )}
              </div>
            )}
            {/* Camera presets */}
            <CameraPresets onSelect={(preset) => appendToPrompt(preset)} />
          </section>

          {/* Parameters — dropdowns for duration + ratio */}
          <section className="panel">
            <div className="section-title">
              <span>Параметры</span>
              <small>{audio ? "генерировать звук" : "без генерации звука"}</small>
            </div>

            {/* Duration — dropdown */}
            <div className="control-group">
              <div className="control-label">Длительность</div>
              <select
                className="param-select"
                value={duration}
                onChange={(e) => setDuration(Number(e.target.value))}
              >
                {config.durations.map((d) => (
                  <option key={d} value={d}>{d} секунд</option>
                ))}
              </select>
            </div>

            {/* Resolution — segments (only 3, stays compact) */}
            <ControlGroup label="Разрешение">
              {config.resolutions.map((item) => (
                <Segment key={item} active={resolution === item} onClick={() => setResolution(item)}>{item}</Segment>
              ))}
            </ControlGroup>

            {/* Ratio — dropdown */}
            <div className="control-group">
              <div className="control-label">Формат</div>
              <select
                className="param-select"
                value={ratio}
                onChange={(e) => setRatio(e.target.value)}
              >
                {config.ratios.map((r) => (
                  <option key={r} value={r}>{r}</option>
                ))}
              </select>
            </div>

            <ControlGroup label="Звук в результате">
              <Segment active={audio} onClick={() => setAudio(true)}>Да</Segment>
              <Segment active={!audio} onClick={() => setAudio(false)}>Нет</Segment>
            </ControlGroup>

            <button className="text-button" type="button" onClick={() => setAdvancedOpen((v) => !v)}>
              {advancedOpen ? "Скрыть точные настройки" : "Negative prompt и seed"}
            </button>

            {advancedOpen && (
              <div className="advanced-grid">
                <label>
                  Negative prompt
                  <textarea className="compact-textarea" value={negativePrompt}
                    onChange={(e) => setNegativePrompt(e.target.value)}
                    placeholder="watermark, text, blur, distorted hands" />
                </label>
                <label>
                  Seed
                  <input value={seed} inputMode="numeric"
                    onChange={(e) => setSeed(e.target.value.replace(/[^\d]/g, ""))}
                    placeholder="пусто = случайно" />
                </label>
              </div>
            )}
          </section>

          {/* Launch */}
          <section className="launch-panel">
            <div>
              <strong>{activeMode.label} / {duration} c / {resolution} / {ratio}</strong>
              <span>{imageFiles.length} фото, {videoFile ? "1 видео" : "без видео"}, {audioFile ? "1 аудио" : "без аудио"}</span>
              <span>{estimatedCost ? `Ориентир: $${estimatedCost.toFixed(4)}` : "Списание будет по AIGate"}</span>
            </div>
            <button className="primary-action" type="button" onClick={handleGenerate} disabled={submitting || booting}>
              {submitting ? "Генерация идёт" : "Запустить видео"}
            </button>
          </section>

          {/* Progress */}
          {generation && (
            <section className={`progress-panel ${generation.status}`}>
              <div className="progress-head">
                <span>{STATUS_LABELS[generation.status] || generation.status}</span>
                <strong>{shownProgress}%</strong>
              </div>
              <div className="progress-track">
                <div style={{ width: `${shownProgress}%` }} />
              </div>
              <div className="timer-grid">
                <div><span>Прошло</span><strong>{formatTime(elapsedSeconds)}</strong></div>
                <div><span>Ориентир</span><strong>до 15:00</strong></div>
              </div>
              <p>{generation.message}</p>
              {generation.resultUrl && generation.status === "completed" && (
                <div className="result-video">
                  <video src={generation.resultUrl} controls playsInline />
                  <a href={generation.resultUrl} download>Скачать видео</a>
                </div>
              )}
            </section>
          )}

          {/* History */}
          {history.length > 0 && (
            <section className="panel recent-results">
              <div className="section-title">
                <span>Последние результаты</span>
                <small>для потока</small>
              </div>
              {history.slice(0, 4).map((item) => (
                <article className="recent-item" key={item.id}>
                  <div>
                    <strong>#{item.id} / {STATUS_LABELS[item.status] || item.status}</strong>
                    <span>{item.quality} / {item.duration} c / {item.resolution} / {item.ratio}</span>
                  </div>
                  {item.result_url && <a href={absoluteUrl(item.result_url)} download>Скачать</a>}
                </article>
              ))}
            </section>
          )}
        </main>
      )}

      {page === "profile" && (
        <main className="settings-grid">
          <section className="panel">
            <div className="section-title">
              <span>Баланс AIGate</span>
              <small>{hasKey ? "ключ подключён" : "нет ключа"}</small>
            </div>
            <pre className="balance-box">{balance || "API-ключ не подключён"}</pre>
            {balanceRaw && <pre className="raw-box">{JSON.stringify(balanceRaw, null, 2)}</pre>}
            <button className="secondary-action" type="button" onClick={loadBalance} disabled={checkingBalance}>
              {checkingBalance ? "Проверяем" : "Обновить баланс"}
            </button>
            <a className="ref-link" href={config.referral_url} target="_blank" rel="noreferrer">Открыть кабинет AIGate</a>
          </section>
          <section className="panel">
            <div className="section-title">
              <span>API-ключ пользователя</span>
              <small>хранится только на backend</small>
            </div>
            <KeyForm onSubmit={handleSaveKey} />
          </section>
        </main>
      )}
    </div>
  );
}

function ControlGroup({ label, children }) {
  return (
    <div className="control-group">
      <div className="control-label">{label}</div>
      <div className="segment-row">{children}</div>
    </div>
  );
}

function Segment({ active, onClick, children }) {
  return (
    <button className={`segment ${active ? "active" : ""}`} onClick={onClick} type="button">
      {children}
    </button>
  );
}

function KeyForm({ onSubmit }) {
  const [key, setKey] = useState("");
  const [saving, setSaving] = useState(false);
  async function submit() {
    setSaving(true);
    try { await onSubmit(key.trim()); setKey(""); } finally { setSaving(false); }
  }
  return (
    <div className="key-form">
      <input type="password" value={key} onChange={(e) => setKey(e.target.value)} placeholder="sk-..." autoComplete="off" />
      <button className="primary-action" type="button" onClick={submit} disabled={saving || !key.trim()}>
        {saving ? "Проверяем ключ" : "Сохранить ключ"}
      </button>
    </div>
  );
}
